-/// Run dcg in hook mode with the given command as JSON input.
-fn run_hook_mode(command: &str) -> (String, String, i32) {
-    let input = format!(
-        r#"{{"tool_name":"Bash","tool_input":{{"command":"{}"}}}}"#,
-        command.replace('\\', "\\\\").replace('"', "\\\"")
-    );
